var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"으윽… 머리야.","JPN":"ううっ……頭が痛い……","ENG":"Ugh... My head...","TWN":"呃呃…我的頭…"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L4_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"괜찮아…? 정신이 들어?","JPN":"大丈夫……？　目は覚めたか？","ENG":"You good...? How are you holding up?","TWN":"還好嗎…？你醒了？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"이 소리… 누가 싸우고 있는 건가?","JPN":"この音は……誰か戦っているのか？","ENG":"That noise... Is someone fighting?","TWN":"這個聲音是…有人在打架嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"학생회 사람들이 우릴 구하러 온 것 같아. 란체스터 학생회장도.","JPN":"生徒会の人たちが俺らを助けにきたようだ。ランチェスター生徒会長も。","ENG":"I think the Student Council is here to save us. The Student President is here too.","TWN":"好像是學生會的人和學生會長來救我們了。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"시엘은…?","JPN":"シエルは……？","ENG":"What about Ciel...?","TWN":"希爾呢…？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"우리랑 같이 있어. 부상이 심해서 아직 의식은 없지만…","JPN":"俺たちと一緒にいるぜ。酷いケガでまだ意識は戻っていないが……","ENG":"She's with us. She's badly injured and hasn't woken up yet...","TWN":"她和我們在一起，但她傷勢太重還沒恢復意識…"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"그런 꼴 사나운 짓을 저질러 놓고도… 또 다른 사람들의 도움을 받다니.","JPN":"あんな下劣極まりないことをしておいて……また他人から助けられるなんて。","ENG":"After what we've done... we're still getting helped by others...","TWN":"我們做出這麼過分的事…她們還願意來救我們。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"한심해…","JPN":"俺たちはなんて情けないんだ……","ENG":"We're pathetic...","TWN":"我們真是糟糕…"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"한심하지 않아.","JPN":"情けなくなんかないさ。","ENG":"You're not pathetic.","TWN":"不需要感到內疚。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"너흰 강해지기 위해, 너희가 할 수 있는 최선을 다 했을 뿐이잖아?","JPN":"お前たちは強くなるために、自分たちにできることを最大限やったまでだろう？","ENG":"All you wanted was to get stronger, and you did the best you could.","TWN":"你們只是盡自己的努力想要變強而已，不是嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"너…!","JPN":"お前は……！","ENG":"You...!","TWN":"你…！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"이 자식! 우릴 속이다니!","JPN":"てめぇ！　俺たちを騙したな！","ENG":"You bastard! You tricked us!","TWN":"你這傢伙！竟敢騙我們！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"하하, 이해 좀 해줘. 아직은 나도 말단직이라 상사가 시키면 어쩔 수 없거든.","JPN":"はは、理解してくれよ。僕だってまだ下っ端だから、上司にやらされたら従うしかないんだ。","ENG":"Haha, try to see it from my point of view. As a low-ranking member of this group, I have to follow my boss's orders.","TWN":"哈哈，你們就體諒我一下，畢竟我只是個基層員工，當然只能聽長官的命令囉。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"처음부터… 우릴 전부 팔아넘길 셈이었던 거야?","JPN":"初めから……俺たちのこと売り渡すつもりだったのか？","ENG":"Were you... planning on betraying us and then selling us off from the start?","TWN":"你從一開始…就打算出賣我們吧？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"애초에 저 이상한 사람들이랑 한통속이었던 거겠지.","JPN":"最初からあの変な連中とグルだったんだろ。","ENG":"He was in it with those strange people from the beginning.","TWN":"你和那些人原本就是一掛的吧？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"으음- 유감스럽게도 한통속은 틀린 말이 아니네.","JPN":"うーん、申し訳ないけど、否定はしないかな。","ENG":"Hmm... You're not wrong about siding with them from the start.","TWN":"嗯嗯，你說的沒錯，我們確實是同一掛的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"하지만 걱정 마. 너희는 내가 풀어주고, 이것도 줄 테니까.","JPN":"でも心配しないで。お前たちのことは僕が解放し、これも渡す。","ENG":"But don't you worry. I'll free the both of you, and also give you this.","TWN":"但你們放心，我會放了你們，還給你們這個。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"이건…?","JPN":"これは……？","ENG":"That's...","TWN":"這是…？"},"stage":{"bg":"POLICE_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"엘릭서.","JPN":"エリクサー。","ENG":"It's the Elixir.","TWN":"聖水。"},"stage":{"bg":"POLICE_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"그 살인마 여자앨 여기로 데려오면 주겠다고 약속했잖아?","JPN":"あの殺人鬼の女をここに連れてきたら、これを渡すと約束したろう？","ENG":"I promised to give this to you if you brought the girl here, didn't I?","TWN":"我不是跟你們說好，只要你們把那個殺人魔帶到這裡來，我就會給你們嗎？"},"stage":{"bg":"POLICE_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"이거… 진짜로 엘릭서야?","JPN":"これは……本当にエリクサーなのか？","ENG":"Is that... really the Elixir?","TWN":"這是…真的聖水？"},"stage":{"bg":"POLICE_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"그러엄- 내 한심한 부하녀석처럼 물은 타지 않았으니 안심해도 돼.","JPN":"もちろんさ。僕の情けない部下みたいに、水で割ったりはしていないから安心しな。","ENG":"Of course! It's pure, 100% Elixir, unlike the diluted one my stupid subordinate sold.","TWN":"正是，你們放心，裡面沒有摻水，我可不像那些無良的手下。"},"stage":{"bg":"POLICE_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"이것만 있으면 두 사람의 인생은 바뀔 거야.","JPN":"これがあれば二人の人生はガラッと変わるだろう。","ENG":"With this, your lives will change completely.","TWN":"只要有它，就可以改變你們二個人的人生。"},"stage":{"bg":"POLICE_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"아카데미의 시시한 교육은 더이상 필요 없을 테고, 오늘처럼 무력하게 당하는 일도 없겠지.","JPN":"アカデミーのくだらない教育も必要なくなり、今日みたいに無力にやられることもなくなる。","ENG":"No longer will you need to learn trivial matters at the Academy, nor will you get pushed over by force like you did today.","TWN":"你們再也不需要學院無聊的教育，也不會再像今天這樣任人擺佈。"},"stage":{"bg":"POLICE_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"축하해.","JPN":"おめでとう。","ENG":"Congratulations.","TWN":"恭喜。"},"stage":{"bg":"POLICE_02","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"시엘을 데려가면… 어떻게 할 셈이야?","JPN":"シエルを連れていって……そのあとはどうするつもりだ？","ENG":"What are you... going to do to Ciel?","TWN":"你把希爾帶走後…打算對她做什麼？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"야! 너 진심으로 하는 소리야?! 지금이라도 이런 거래는 때려치우고…!","JPN":"おい！　お前本気なのか！？　今からでもそんな取引なんか断っ……！","ENG":"Hey! You can't be serious right now! We have to break off this deal, and–!","TWN":"喂！你是認真的嗎？趁現在趕快取消交易才…！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"시끄러!","JPN":"うるさい！","ENG":"Shut up!","TWN":"你閉嘴！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"그 애는 살인마라고. 시엘도 그렇다고 인정했잖아.","JPN":"あいつは殺人鬼だ。本人もそう認めていただろう。","ENG":"She's a murderer, remember? She even admitted it.","TWN":"希爾是殺人魔欸！而且她自己也不否認不是嗎！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"애초에 D급인 우리가 이 상황에서 뭘 할 수 있는데?","JPN":"そもそもな、この状況でD級の俺たちにできることなんか何もないんだよ！","ENG":"Plus, what can a couple of Grade D Counters do in this situation?","TWN":"像我們這種D級制裁者，在這種情況下本來就無能為力。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"그, 그건…","JPN":"そ、それは……","ENG":"W-well...","TWN":"我…"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"하하, 너무 걱정하진 마. 해치진 않겠다고 맹세해.","JPN":"はは、そんなに心配しなくてもいいよ。傷つけるつもりはない。","ENG":"Haha, don't be so serious. I won't hurt her. I can promise you that.","TWN":"哈哈，放心，我發誓，我不會傷害她。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"난 오히려 살인마였을 뿐인 그녀가 자신의 힘을 올바른 곳에 쓸 수 있도록 교화시켜주려는 것뿐이거든.","JPN":"むしろただの殺人鬼だったあの子が、自分の力を正しく使えるように、更生してあげようとしているだけだ。","ENG":"All I wanted was to help her use her abilities for the better. A correction, if you will.","TWN":"我反而會教化原本是殺人魔的她，讓她的力量可以用再對的地方。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"…그럼 데려가.","JPN":"……じゃあ連れていけ。","ENG":"...Then you can take her.","TWN":"…那你把人帶走吧。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"아무에게도 말하지 않을 테니까.","JPN":"誰にも言わないから。","ENG":"We won't tell anyone.","TWN":"我不會跟任何人說的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"좋아. 그럼 우리의 거래는 이걸로 끝이네.","JPN":"よし、じゃあ僕たちの取引はこれで成立だね。","ENG":"Very well. It's a deal.","TWN":"好，那我們的交易就到此結束。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"받아.","JPN":"はい、どうぞ。","ENG":"Here.","TWN":"拿去吧。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"크윽…!","JPN":"くうっ……！","ENG":"Kgh...!","TWN":"咕嚕…！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RINGING"},{"id":"L4_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"오? 받자마자 쓰는 거야?","JPN":"おお？　貰ってすぐに飲むなんて！","ENG":"Oh? Using it already?","TWN":"喔？一拿到就立刻使用嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"그렇게 한 번에 투여하면 후폭풍이 장난이 아닐 텐…","JPN":"そんなに一気に体内に入れたら、相当な跳ね返りが……","ENG":"But be careful not to use too much, or the aftereffects are going to be–","TWN":"但你一下就用光的話，副作用會很厲…"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"…지금 날 공격한 거. 실수라고 하진 않겠지?","JPN":"……今の攻撃、偶然じゃないよね？","ENG":"That attack... I'm guessing it wasn't a mistake, was it?","TWN":"…剛才的攻擊，不是失誤吧？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"너야말로 시엘을 저런 꼴로 만들어 놓고는… 해칠 마음이 없다고?","JPN":"お前こそシエルをあんなにして……傷つけるつもりがないだと？","ENG":"You really want us to believe that you won't hurt her... after what you've already done to her?","TWN":"我才要問你，你把希爾弄成那副慘樣…還說不會傷害她？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"시엘은… 우리가 속이 시커먼 놈들이란 걸 알면서도! 거짓말은 하지 않았어!","JPN":"シエルは……俺たちの黒い腹の底を知っていながらも……！　嘘はつかなかった！","ENG":"Ciel... She knew what kind of bad people we were! But still, she didn't lie to us!","TWN":"希爾她…明知道我們想害她！她也沒有說謊！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"커허억…!","JPN":"ぐはあっ！！","ENG":"Kuh...!","TWN":"唔呃呃…！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"푸하핫! 뭘 혼자 고꾸라지는 거야?","JPN":"うははっ！　何一人でぶっ倒れているんだ？","ENG":"Bwahahaha! Why are you suddenly falling to the ground?","TWN":"噗哈哈！你怎麼連站都站不好？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"괘, 괜찮아?!","JPN":"だ、大丈夫か？","ENG":"Y-you okay?!","TWN":"你，你沒事吧？！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"아니… 온몸의 혈관이 뒤틀리는 것 같아.","JPN":"いや……まるで身体中の血管が歪んでいるみたいだ。","ENG":"I don't think so... It feels like all my veins are being twisted.","TWN":"我全身的血管…好像快炸開一樣。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"이 자식…! 역시 우릴 속이고 가짜 엘릭서를 준 거였지?!","JPN":"この野郎……！　やっぱり俺たちを騙して偽のエリクサーを渡したな！？","ENG":"You bastard...! I knew you were fooling us again with another fake Elixir!","TWN":"你這傢伙…！你果然是騙我們的，這是假的聖水吧？！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"그건 너희가 찾던 진짜 엘릭서가 맞아.","JPN":"それはお前たちが求めていた本物のエリクサーだよ。","ENG":"No, that is a genuine Elixir I gave you.","TWN":"這就是你們想要的真正的聖水沒錯。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"내가 말하지 않았던가? 엘릭서라는 건 원래 상성을 좀 타는 물건이라고.","JPN":"言わなかったか？　エリクサーには相性があるんだ。","ENG":"Didn't I tell you before? The Elixir works differently for everyone.","TWN":"我沒說過嗎？聖水也是會挑人的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"뭐…?","JPN":"何だと……？","ENG":"What...?","TWN":"什麼…？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"단지 네가 D급에 엘릭서와도 상성이 맞지 않는, 최악의 카운터였을 뿐이란 거지.","JPN":"つまり、お前はD級で、エリクサーとの相性も悪い、これでもかというほど最悪のカウンターだったってだけだ。","ENG":"It just means that you are the worst Counter to live–a Grade D who's incompatible with the Elixir.","TWN":"這就表示，你這個D級和聖水不相容，是個失敗的制裁者。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"그… 그럴 수가…","JPN":"そ、そんな……","ENG":"N-no way...","TWN":"怎…怎麼會…"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"끄헉!","JPN":"くはっ……！","ENG":"Kuh...!","TWN":"呃呃！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"그건 그거고, 이건 이거야.","JPN":"ただそれはそれ、これはこれだ。","ENG":"It is what it is.","TWN":"一碼歸一碼。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"감히 내 뒤통수를 치려 한 대가는… 제대로 치러야겠지?","JPN":"僕を裏切ろうとするなんて……それなりの覚悟はできているよな？","ENG":"Now, I believe it's time you paid the price for trying to stab me in the back.","TWN":"攻擊我的代價就是…要好好教訓你一頓吧？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"…안돼! 그만둬!","JPN":"……ダメだ！　やめろ！","ENG":"...No! Stop it!","TWN":"…不可以！住手！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L36_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"음…?","JPN":"む……？","ENG":"Mm...?","TWN":"嗯…？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"여기에 있었군요. 소란 덕분에 찾았어요.","JPN":"ここにいたんですね。随分と騒がしかったのですぐわかりました。","ENG":"There you are. You saved me the trouble of finding you with all the noise you made.","TWN":"原來在這裡，我聽到你們爭吵的聲音才找到這裡的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"하… 학생회장…!","JPN":"あ……生徒会長……！","ENG":"M-Ms. President...!","TWN":"學… 學生會長…！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"학생회장? 당신의 역량으론 병사들을 벌써 전부 해치울 리 없을 텐데?","JPN":"生徒会長？　お前一人でこんなに早く兵士たちを倒せるわけが……","ENG":"Ms. President? But you couldn't have defeated all those men by yourself...","TWN":"學生會長？以你的能耐，應該無法這麼快就把那些士兵都處理掉吧？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아카데미의 훌륭한 두 학생이 붙잡힌 친구들을 구해달라며 길을 열어줬습니다.","JPN":"アカデミーの素晴らしい生徒お二人が友人を助けてくれと言いながら、道を開けてくれました。","ENG":"Two of the Academy's excellent students cleared the path for me so I could save their friends.","TWN":"因為有二位學院傑出的學生要來救被綁架的朋友，於是便替我開路。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저 또한 당신을 잡는 게 최우선이니까요.","JPN":"私もまた、あなたを捕らえることが先でしたので。","ENG":"I also put my priorities on catching you first.","TWN":"而抓到你也是我的首要之務。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"하하… 이런.","JPN":"はは……参ったな。","ENG":"Haha... Oh, dear.","TWN":"哈哈…糟糕。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"학교에선 나름 눈에 안 띄게 지냈다고 생각했는데, 고귀한 학생회장님께서 날 눈독 들이고 있을 줄은 몰랐는걸?","JPN":"学校では完璧に存在を消していたはずだが、高貴な生徒会長様がわざわざ僕に目をつけていたとは驚きだね。","ENG":"I thought I did a good job laying low at the Academy. Who would've thought that the Student President herself would've had her eyes on me?","TWN":"我以為我在學校過得蠻低調的，沒想到竟然會被高貴的學生會長盯上？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"백서의 파문인, 타오 파우스트.","JPN":"白西の追放者、タオ・ファウスト。","ENG":"Outcast of White West, Tao Faust.","TWN":"你是被白西逐出師門的弟子，陶·浮士德。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"당신의 행보는 제가 여기서 멈추겠습니다.","JPN":"あなたの悪事は、ここで私が食い止めます。","ENG":"Your heinous misdeeds stop here.","TWN":"我不會再讓你繼續胡作非為。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"내 본명을 알고 있다니.","JPN":"僕の本名を知っているのか。","ENG":"So you even know my name.","TWN":"竟然知道我的本名？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"넌 누구지?","JPN":"お前は誰だ？","ENG":"Who are you?","TWN":"你是誰？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"백서는 당신이 규율을 어기고 추방됐을 때부터 주시하고 있었어요.","JPN":"白西はあなたが規律を破り、追放されたときから、ずっと注視していました。","ENG":"White West has been watching you ever since you were banished from the sect for breaking the law.","TWN":"白西因為你違反門規將你逐出師門時，我就一直在監視你。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"네가 백서가 기르는 개라고…?","JPN":"まさかお前が白西の犬だというのか……？","ENG":"You're White West's hound...?","TWN":"你是白西養的走狗…？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"어쩐지, 그 깐깐한 백서의 사범들이 날 너무 쉽게 놓아준다 싶더니. 그런 음흉한 속내가 있었군.","JPN":"なるほど、どおりであの粘着質な白西の師範どもが、簡単に僕を見逃してくれたわけだ。企みがあったのか。","ENG":"Now it makes sense. No wonder those strict White West mentors let me go so easily. They had their own agenda.","TWN":"難怪，我還想說白西的人那麼死腦筋，怎麼可能輕易放過我，原來是有陰謀的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"본래대로라면 만무제에서 사용된 약물의 정체를 밝혀내고 당신이 속한 집단의 수뇌부까지 파헤쳐 뿌리째 뽑는 것이 계획이었습니다만…","JPN":"本来なら万武際で使われた薬物の正体を突き止め、あなたの裏にいる組織の首脳部まで根こそぎ始末するのが計画でしたが……","ENG":"Originally, our intention was to reveal what kind of drug you used during the Great Martial Arts Tournament, then root out the organization you were in after finding out who its leader was...","TWN":"原本是打算查清楚你在武林大會中所使用的藥物後，再將你所屬的集團首腦全部一網打盡，…"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"당신이 아카데미의 학생들에게 손을 댄 이상, 더는 좌시할 수 없어졌죠.","JPN":"あなたがアカデミーの生徒たちに手を出した以上、これ以上座視はできなくなりました。","ENG":"But since you hurt one of our students, I could not wait any longer.","TWN":"但當你將手伸向學院的學生後，我便無法再坐視不管。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"그래? 계획대로 되지 않아서 참 유감이네.","JPN":"そうかい？　計画が思うように上手くいかなかったようで残念だ。","ENG":"Oh yeah? I'm sorry it didn't go as you planned.","TWN":"是嗎？很遺憾你們的計畫失敗。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"그런데…","JPN":"ところで……","ENG":"But still...","TWN":"不過…"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"날 잡겠다면서, 고작 너 혼자로 충분하다고 생각한 거야?","JPN":"僕を捕まえるのに、お前一人で十分だと思ったのか？","ENG":"You think you can catch me all by yourself?","TWN":"你覺得光憑你一個人就能夠對付我嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};